import { ComponentModule } from '@/main';
import { SIGNATURE_CLEAR_ALL, SIGNATURE_SAVE } from '@/models/events';
import SignaturePad from 'signature_pad';

export default {
    name: () => 'signature',
    template: () => import('./signature.html?raw'),
    data: () => ({
        signature: null as SignaturePad | null,
        init() {
            console.log('signature@init');

            this.$nextTick(() => {
                const canvas = this.$refs.signatureCanvas as HTMLCanvasElement | null;

                if (canvas === null) {
                    return;
                }

                this.signature = new SignaturePad(canvas);

                this.signature.addEventListener(
                    'endStroke',
                    () => {
                        const parent: HTMLElement | null = canvas.closest('[data-signature]');
                        if (null !== parent && !this.signature.isEmpty()) {
                            this.$dispatch(SIGNATURE_SAVE, {
                                key: parent.dataset.signature,
                                value: this.signature.toDataURL(), // PNG
                            });
                        }
                    },
                    { once: false },
                );

                // @ts-expect-error 2769
                window.addEventListener(SIGNATURE_CLEAR_ALL, (e: CustomEvent) => {
                    this.signature.clear();
                });
            });
        },
    }),
} as ComponentModule;

